let channelId = '';
let onlyMissingViews = true;
let maxPosts = 80;
let useEngagementFallback = true;
try {
  const wh = $('Webhook 갱신').all();
  if (wh.length) {
    const raw = wh[0].json;
    const b = raw.body ?? raw;
    const parsed = typeof b === 'string' ? JSON.parse(b) : b;
    if (parsed?.channelId) channelId = String(parsed.channelId).trim();
    if (parsed?.onlyMissingViews != null) onlyMissingViews = Boolean(parsed.onlyMissingViews);
    if (parsed?.maxPosts != null) maxPosts = Number(parsed.maxPosts);
    if (parsed?.useEngagementFallback != null) useEngagementFallback = Boolean(parsed.useEngagementFallback);
  }
} catch { /* manual / schedule */ }
if (!Number.isFinite(maxPosts) || maxPosts < 1) maxPosts = 80;
const base = ($env.DASHBOARD_API_URL || 'http://host.docker.internal:3000').replace(/\/$/, '');
const secret = $env.DASHBOARD_API_SECRET || '';
if (!secret) {
  return [{ json: {
    ok: false,
    skipCall: true,
    message: 'n8n 환경변수 DASHBOARD_API_SECRET 이 없습니다. docker-compose.n8n.yml · .env.local 을 확인하세요.',
  } }];
}
return [{ json: {
  channelId,
  onlyMissingViews,
  maxPosts,
  useEngagementFallback,
  source: 'n8n',
  skipCall: false,
  apiUrl: `${base}/api/dashboard/naver-blog-views`,
  apiSecret: secret,
} }];

const cfg = $('기준·API 설정').first().json;
const items = $input.all();
const raw = items[0]?.json;
let body = raw;
if (typeof raw === 'string') {
  try { body = JSON.parse(raw); } catch { body = { ok: false, message: raw.slice(0, 500) }; }
}
if (body?.body && typeof body.body === 'object') body = body.body;
const ok = body?.ok !== false;
return [{ json: {
  ok,
  mode: 'n8n',
  source: cfg.source || 'n8n',
  processed: body?.processed ?? 0,
  updated: body?.updated ?? 0,
  withReadViews: body?.withReadViews ?? 0,
  withEngagementMetric: body?.withEngagementMetric ?? 0,
  skipped: body?.skipped ?? 0,
  failed: body?.failed ?? 0,
  message: body?.message || (ok ? '네이버 블로그 메트릭 갱신 완료' : '갱신 실패'),
  errors: body?.errors ?? [],
  timestamp: new Date().toISOString(),
} }];

const cfg = $input.first().json;
return [{ json: {
  ok: false,
  mode: 'n8n',
  message: cfg.message || '설정 오류',
  timestamp: new Date().toISOString(),
} }];
